+    /// Handle a macrotask by resolving/rejecting Promises or dispatching events.
+    fn handle_macrotask(
+        &self,
+        ctx: &Ctx<'_>,
+        task: &crate::scheduler::Macrotask,
+    ) -> rquickjs::Result<()> {
+        use crate::scheduler::MacrotaskKind as SMK;
