+                obj.set("ok", false)?;
+                obj.set("code", code.clone())?;
+                obj.set("message", message.clone())?;
+                obj
+            }
+        };
+        complete_fn.call::<_, ()>((call_id, js_outcome))?;
+        Ok(())
+    }
